#include <iostream>
#include <vector>

// Node structure for singly linked list
struct Node {
    int data;
    Node* next;

    Node(int x) : data(x), next(NULL) {}
};

// Doubly linked list class
class DoublyLinkedList {
public:
    Node* head;
    Node* tail;

    DoublyLinkedList() : head(NULL), tail(NULL) {}

    void addNode(int data) {
        Node* newNode = new Node(data);
        if (head == NULL) {
            head = newNode;
            tail = newNode;
        } else {
            tail->next = newNode;
            newNode->prev = tail;
            tail = newNode;
        }
    }

    void printList() {
        Node* current = head;
        while (current != NULL) {
            std::cout << current->data << ' '; current = current->next; }
        std::cout << '\n';
    }

    void sortList(Node** head) {
        if (*head == NULL) return;

        Node* current = *head;
        while (current != NULL) {
            Node* next = current->next;
            current->next = NULL;
            current = next;
        }

        *head = mergeLists(*head);
    }

    Node* mergeLists(Node* head1, Node* head2) {
        if (head1 == NULL) return head2;
        if (head2 == NULL) return head1;

        Node* dummy = new Node(0);
        Node* current = dummy;

        while (head1 && head2) {
            if (head1->data < head2->data) {
                current->next = head1;
                head1 = head1->next;
            } else {
                current->next = head2;
                head2 = head2->next;
            }
            current = current->next;
        }

        if (head1) current->next = head1;
        else current->next = head2;

        Node* tail = current->next;
        while (tail->next) tail = tail->next;

        return dummy->next;
    }
};

int main() {
    DoublyLinkedList dll;

    int n;
    std::cin >> n;

    for (int i = 0; i < n; ++i) {
        int x;
        std::cin >> x;
        dll.addNode(x);
    }

    dll.sortList(&dll.head);

    dll.printList();

    return 0;
}
